   782→    // Audio level meter using Web Audio API
   783→    function startAudioLevelMeter(stream) {
   784→      try {
   785→        audioContext = new (window.AudioContext || window.webkitAudioContext)();
   786→        const source = audioContext.createMediaStreamSource(stream);
   787→        audioAnalyser = audioContext.createAnalyser();
   788→        audioAnalyser.fftSize = 256;
   789→        audioAnalyser.smoothingTimeConstant = 0.8;
   790→        source.connect(audioAnalyser);
   791→
   792→        const dataArray = new Uint8Array(audioAnalyser.frequencyBinCount);
   793→
   794→        function updateLevel() {
   795→          if (!audioAnalyser) return;
   796→
   797→          audioAnalyser.getByteFrequencyData(dataArray);
   798→
   799→          // Calculate average level
   800→          let sum = 0;
   801→          for (let i = 0; i < dataArray.length; i++) {
   802→            sum += dataArray[i];
   803→          }
   804→          const avg = sum / dataArray.length;
   805→          const level = Math.min(100, (avg / 128) * 100);
   806→
   807→          // Update both mic level bars
   808→          const previewFill = document.getElementById('mic-level-fill');
   809→          const recordingFill = document.getElementById('recording-mic-level');
   810→
   811→          if (previewFill) previewFill.style.width = level + '%';
   812→          if (recordingFill) recordingFill.style.width = level + '%';
   813→
   814→          micLevelAnimationId = requestAnimationFrame(updateLevel);
   815→        }
   816→
   817→        updateLevel();
   818→      } catch (err) {
   819→        console.warn('Audio level meter not available:', err);
   820→      }
   821→    }
