    13→// Start a new interview
    14→router.post('/start', authMiddleware, async (req, res) => {
    15→  try {
    16→    const { job_id, job_title, job_description, interview_type = 'mock' } = req.body;
    17→
    18→    // Generate questions using AI
    19→    const questions = await generateInterviewQuestions(
    20→      job_title || 'Software Developer',
    21→      job_description,
    22→      5
    23→    );
    24→
    25→    // Create interview record
    26→    const result = await pool.query(
    27→      `INSERT INTO interviews (user_id, job_id, interview_type, questions, status)
    28→       VALUES ($1, $2, $3, $4, 'in_progress')
    29→       RETURNING *`,
    30→      [req.user.id, job_id, interview_type, JSON.stringify(questions)]
    31→    );
    32→
    33→    // Track mock interview start
    34→    try {
    35→      await pool.query(
    36→        'INSERT INTO events (event_type, user_id, metadata) VALUES ($1, $2, $3)',
