    38→      );
    39→    } catch (e) {
    40→      console.error('Failed to log interview start event:', e);
    41→    }
    42→
    43→    res.json({
    44→      success: true,
    45→      interview: result.rows[0],
    46→      questions: questions.map((q, i) => ({
    47→        index: i,
    48→        question: q.question,
    49→        category: q.category,
    50→        difficulty: q.difficulty
    51→      }))
    52→    });
    53→  } catch (err) {
    54→    console.error('Start interview error:', err);
    55→    res.status(500).json({ error: 'Failed to start interview' });
    56→  }
    57→});
