    59→// Submit response to a question
    60→router.post('/:id/respond', authMiddleware, async (req, res) => {
    61→  try {
    62→    const { question_index, response_text, video_url } = req.body;
    63→
    64→    // Get interview
    65→    const interview = await pool.query(
    66→      'SELECT * FROM interviews WHERE id = $1 AND user_id = $2',
    67→      [req.params.id, req.user.id]
    68→    );
    69→
    70→    if (interview.rows.length === 0) {
    71→      return res.status(404).json({ error: 'Interview not found' });
    72→    }
    73→
    74→    const interviewData = interview.rows[0];
    75→    const questions = interviewData.questions;
    76→    const question = questions[question_index];
    77→
    78→    if (!question) {
    79→      return res.status(400).json({ error: 'Invalid question index' });
    80→    }
    81→
    82→    // Analyze response with AI
    83→    const analysis = await analyzeInterviewResponse(
    84→      question.question,
    85→      response_text,
    86→      question.key_points || [],
    87→      { subscriptionId: req.user.stripe_subscription_id }
    88→    );
    89→
    90→    // Update responses array
    91→    const responses = interviewData.responses || [];
    92→    responses[question_index] = {
    93→      question_index,
    94→      response_text,
    95→      video_url,
    96→      analysis,
    97→      submitted_at: new Date().toISOString()
    98→    };
    99→
   100→    // Update video URLs if provided
   101→    const videoUrls = interviewData.video_urls || [];
   102→    if (video_url) {
   103→      videoUrls[question_index] = video_url;
   104→    }
   105→
   106→    await pool.query(
   107→      `UPDATE interviews SET responses = $1, video_urls = $2, updated_at = NOW()
   108→       WHERE id = $3`,
   109→      [JSON.stringify(responses), JSON.stringify(videoUrls), req.params.id]
   110→    );
   111→
   112→    res.json({
   113→      success: true,
   114→      analysis,
   115→      questions_remaining: questions.length - responses.filter(r => r).length
   116→    });
   117→  } catch (err) {
   118→    console.error('Submit response error:', err);
   119→    res.status(500).json({ error: 'Failed to submit response' });
   120→  }
   121→});
