// Initialize
document.addEventListener('DOMContentLoaded', async () => {
  const user = await checkAuth();
  if (!user) {
    window.location.href = '/login.html';
    return;
  }

  // Get job ID from URL if present
  const urlParams = new URLSearchParams(window.location.search);
  const jobId = urlParams.get('job_id');
  if (jobId) window._interviewJobId = jobId;

  // Step 1: Request camera AND microphone access (separate from video analyzer)
  try {
    mediaStream = await navigator.mediaDevices.getUserMedia({
      video: { width: 1280, height: 720 },
      audio: {
        echoCancellation: true,
        noiseSuppression: true,
        autoGainControl: true
      }
    });

    const previewVideo = document.getElementById('preview-video');
    previewVideo.srcObject = mediaStream;

    // Explicitly play to ensure video starts in all browsers
    try { await previewVideo.play(); } catch (e) { console.warn('Autoplay handled by attribute'); }

    document.getElementById('preview-overlay').style.display = 'none';

    // Verify audio tracks are present and active
    const audioTracks = mediaStream.getAudioTracks();
    if (audioTracks.length === 0) {
      console.error('No audio tracks in stream');
      updateMicStatus('error', 'Microphone not detected');
    } else {
      const audioTrack = audioTracks[0];
      console.log('Audio track:', audioTrack.label, 'enabled:', audioTrack.enabled, 'muted:', audioTrack.muted);

      if (!audioTrack.enabled) {
        audioTrack.enabled = true;
      }

      updateMicStatus('active', `Mic: ${audioTrack.label || 'Active'}`);

      // Start audio level visualization
      startAudioLevelMeter(mediaStream);
    }
  } catch (err) {
    console.error('Camera/microphone access error:', err);
    const overlay = document.getElementById('preview-overlay');

    if (err.name === 'NotAllowedError') {
      updateMicStatus('error', 'Permission denied');
      overlay.innerHTML = `
        <div style="text-align:center;">
          <h3 style="font-size: 1.5rem; margin-bottom: 1rem;">⚠️ Permission Required</h3>
          <p style="margin-bottom: 1rem; opacity: 0.8;">Please allow camera and microphone access in your browser</p>
          <button class="btn btn-primary" onclick="location.reload()" style="background:linear-gradient(135deg,#10b981,#3b82f6);color:#fff;border:none;padding:0.75rem 1.5rem;border-radius:10px;cursor:pointer;font-weight:600;">🔄 Try Again</button>
        </div>`;
    } else if (err.name === 'NotFoundError') {
      updateMicStatus('error', 'No devices found');
      overlay.innerHTML = `
        <div style="text-align:center;">
          <h3 style="font-size: 1.5rem; margin-bottom: 1rem;">📷 Device Not Found</h3>
          <p style="margin-bottom: 1rem; opacity: 0.8;">Connect a camera and microphone, then try again</p>
          <button class="btn btn-primary" onclick="location.reload()" style="background:linear-gradient(135deg,#10b981,#3b82f6);color:#fff;border:none;padding:0.75rem 1.5rem;border-radius:10px;cursor:pointer;font-weight:600;">🔄 Try Again</button>
        </div>`;
    } else {
      updateMicStatus('error', 'Setup error');
      overlay.innerHTML = `
        <div style="text-align:center;">
          <h3 style="font-size: 1.5rem; margin-bottom: 1rem;">⚠️ Camera Setup Failed</h3>
          <p style="margin-bottom: 1rem; opacity: 0.8;">${err.message || 'Unknown error'}</p>
          <button class="btn btn-primary" onclick="location.reload()" style="background:linear-gradient(135deg,#10b981,#3b82f6);color:#fff;border:none;padding:0.75rem 1.5rem;border-radius:10px;cursor:pointer;font-weight:600;">🔄 Try Again</button>
        </div>`;
    }
  }

  // Step 2: Initialize video analyzer separately (never breaks camera/mic)
  try {
    if (typeof VideoAnalyzer !== 'undefined') {
      videoAnalyzer = new VideoAnalyzer();
      const initialized = await videoAnalyzer.init();

      if (initialized) {
        console.log('Video analyzer ready');
        videoAnalyzer.on('scores', (scores) => {
          updateLiveMetrics(scores);
        });
      } else {
        console.warn('Video analyzer init failed — continuing without AI analysis');
      }
    }
  } catch (err) {
    console.warn('Video analyzer not available:', err);
    // Camera/mic still works fine without the analyzer
  }
});

